import axios from './lib/axios.js';

// 1. Define the interceptor function to avoid repetition
const add404Interceptor = (instance) => {
    instance.interceptors.response.use(
        (response) => response,
        (error) => {
            if (error.response?.status === 404) {
                return Promise.resolve({ data: null, status: 404 });
            }
            return Promise.reject(error);
        }
    );
};

// 2. Apply to the default export
add404Interceptor(axios);

// 3. Create a wrapper for 'create'
const customCreate = (config) => {
    const instance = axios.create(config);
    add404Interceptor(instance);
    return instance;
};

// ... (your existing const destructuring)

export {
    axios as default,
    customCreate as create, // Export the wrapped version
    Axios,
    AxiosError,
    // ... (keep the rest of your exports)
};